async def _get_storefront_config() -> dict:
    defaults = _default_storefront_config()
    await db.settings.update_one(
        {'_id': 'storefront_config'},
        {'$setOnInsert': defaults},
        upsert=True,
    )
    config = await db.settings.find_one({'_id': 'storefront_config'}) or defaults
    how_it_works = config.get('how_it_works') or {}
    steps = [step for step in (how_it_works.get('steps') or []) if isinstance(step, dict)]
    return {
        '_id': 'storefront_config',
        'hero_banners': [str(url or '').strip() for url in (config.get('hero_banners') or []) if str(url or '').strip()],
        'how_it_works': {
            'title': str(how_it_works.get('title') or defaults['how_it_works']['title']).strip(),
            'subtitle': str(how_it_works.get('subtitle') or defaults['how_it_works']['subtitle']).strip(),
            'steps': [
                {
                    'title': str(step.get('title') or '').strip(),
                    'description': str(step.get('description') or '').strip(),
                    'icon': str(step.get('icon') or 'fa-circle').strip() or 'fa-circle',
                }
                for step in steps
                if str(step.get('title') or '').strip() or str(step.get('description') or '').strip()
            ] or defaults['how_it_works']['steps'],
        },
        'best_sellers': [str(key or '').strip() for key in (config.get('best_sellers') or []) if str(key or '').strip()],
        'updated_at': config.get('updated_at') or defaults['updated_at'],
    }


def _normalize_store_role(value: Any) -> str:
    role = str(value or 'customer').strip().lower()
    if role in STORE_STAFF_ROLES:
        return role
    return 'customer'


def _is_staff_role(value: Any) -> bool:
    return _normalize_store_role(value) in STORE_STAFF_ROLES


