def _normalize_catalog_category(category: dict | None) -> dict:
    raw = dict(category or {})
    raw['_id'] = str(raw.get('_id') or '').strip()
    raw['name'] = str(raw.get('name') or '').strip()
    raw['icon'] = str(raw.get('icon') or 'fa-gamepad').strip() or 'fa-gamepad'
    raw['image'] = str(raw.get('image') or '').strip()
    raw['logo'] = str(raw.get('logo') or '').strip()
    raw['description'] = _normalize_catalog_description(raw.get('description'))
    raw['estimated_completion_time'] = _normalize_catalog_eta(raw.get('estimated_completion_time'))
    raw['is_active'] = _normalize_catalog_active(raw.get('is_active'), True)
    return raw


