def _payment_fee_mode(fee_doc: Any) -> str:
    mode = str((fee_doc or {}).get('mode') or 'fixed').strip().lower()
    return mode if mode in {'fixed', 'percentage'} else 'fixed'


def _payment_fee_value(fee_doc: Any) -> float:
    try:
        return max(float((fee_doc or {}).get('value') or 0), 0.0)
    except (TypeError, ValueError):
        return 0.0


def _compute_wallet_fee(amount: float, fee_doc: Any) -> float:
    mode = _payment_fee_mode(fee_doc)
    value = _payment_fee_value(fee_doc)
    if mode == 'percentage':
        return round(max(float(amount or 0), 0.0) * value / 100.0, 2)
    return round(value, 2)


def _normalize_payment_method(doc: dict | None) -> dict:
    raw = dict(doc or {})
    tax_fee = raw.get('tax_fee') if isinstance(raw.get('tax_fee'), dict) else {}
    method_type = str(raw.get('type') or 'both').strip().lower()
    if method_type not in {'deposit', 'withdrawal', 'both'}:
        method_type = 'both'
    return {
        '_id': str(raw.get('_id') or uuid.uuid4().hex),
        'name': str(raw.get('name') or '').strip(),
        'image_url': str(raw.get('image_url') or '').strip(),
        'type': method_type,
        'is_active': _normalize_catalog_active(raw.get('is_active'), True),
        'tax_fee': {
            'mode': _payment_fee_mode(tax_fee),
            'value': _payment_fee_value(tax_fee),
        },
        'created_at': raw.get('created_at') or _utcnow(),
        'updated_at': raw.get('updated_at') or _utcnow(),
    }


def _serialize_payment_method(method: dict) -> dict:
    normalized = _normalize_payment_method(method)
    fee = normalized['tax_fee']
    return {
        'id': normalized['_id'],
        'name': normalized['name'],
        'image_url': normalized['image_url'],
        'type': normalized['type'],
        'is_active': normalized['is_active'],
        'tax_fee': fee,
        'fee_label': f"{fee['value']:.2f}%" if fee['mode'] == 'percentage' else f"{fee['value']:.2f}",
        'updated_at': _iso_datetime_string(normalized['updated_at']),
    }


