def _thread_id_for_chat(chat_type: str, entity_id: str) -> str:
    chat_type = str(chat_type or 'ticket').strip().lower()
    entity_id = str(entity_id or '').strip()
    if chat_type == 'order':
        return _order_thread_id(entity_id)
    if chat_type == 'wallet':
        return _wallet_thread_id(entity_id)
    return _ticket_thread_id(entity_id)


def _chat_type_from_thread_id(thread_id: str) -> tuple[str, str]:
    raw = str(thread_id or '').strip()
    if raw.startswith('order_'):
        return 'order', raw.split('_', 1)[1]
    if raw.startswith('wallet_'):
        return 'wallet', raw.split('_', 1)[1]
    return 'ticket', raw


async def _run_transaction(operation):
    try:
        async with await db.client.start_session() as session:
            async with session.start_transaction():
                return await operation(session)
    except (OperationFailure, AttributeError, TypeError):
        return await operation(None)


def _utcnow() -> datetime:
    return datetime.now(timezone.utc)


def _coerce_utc_datetime(value: Any) -> datetime | None:
    if not value:
        return None

    if isinstance(value, datetime):
        return value if value.tzinfo else value.replace(tzinfo=timezone.utc)

    raw = str(value).strip()
    if not raw:
        return None

    for fmt in ('%Y-%m-%d %H:%M', '%Y-%m-%d %H:%M:%S'):
        try:
            return datetime.strptime(raw, fmt).replace(tzinfo=timezone.utc)
        except ValueError:
            continue

    try:
        parsed = datetime.fromisoformat(raw)
    except ValueError:
        return None

    return parsed if parsed.tzinfo else parsed.replace(tzinfo=timezone.utc)


def _normalize_email(email: str) -> str:
    return (email or '').strip().lower()


def _hash_sha256(value: str) -> str:
    return hashlib.sha256(value.encode('utf-8')).hexdigest()


def hash_password(password: str) -> str:
    return generate_password_hash(password, method='pbkdf2:sha256:600000', salt_length=16)


def _is_legacy_sha256_hash(value: str) -> bool:
    return bool(value) and len(value) == 64 and all(ch in '0123456789abcdef' for ch in value.lower())


def verify_password(password: str, stored_hash: str) -> bool:
    if not stored_hash:
        return False

    if _is_legacy_sha256_hash(stored_hash):
        return hmac.compare_digest(stored_hash, _hash_sha256(password))

    try:
        return check_password_hash(stored_hash, password)
    except ValueError:
        return False


def check_auth(request: Request):
    incoming = request.cookies.get('admin_session') or ''
    expected = SECRET_TOKEN or ''
    return bool(incoming and expected and hmac.compare_digest(incoming, expected))


